@RequestMapping("/api/vehicle_entries")
@PreAuthorize("isAuthenticated()")
public class VehicleController {
    @GetMapping
    public Page<VehicleDTO> list(@AuthenticationPrincipal User user, Pageable pageable) {
        return repo.findByOwnerId(user.getId(), pageable).map(mapper::toDto);
    }

    @PostMapping
    public ResponseEntity<VehicleDTO> create(@RequestBody @Valid VehicleCreateDTO dto, @AuthenticationPrincipal User user) {
        Vehicle entity = mapper.toEntity(dto);
        entity.setOwnerId(user.getId());
        return ResponseEntity.status(201).body(mapper.toDto(repo.save(entity)));
    }
